static void createPurchaseOrderWithWorkflow(Args _args)
{
    PurchTable          purchTable;
    PurchLine           purchLine;
    PurchTableType      purchTableType;
    VendTable           vendTable;
    InventTable         inventTable;
    NumberSeq           numberSeq;
    boolean             workflowEnabled;
    ;

    // Start transaction to ensure data consistency
    ttsbegin;

    try
    {
        // Find the vendor - replace with your vendor account
        vendTable = VendTable::find('V-10001');
        if (!vendTable)
        {
            throw error("Vendor not found");
        }

        // Create new purchase order header
        purchTable.clear();
        purchTable.initValue();  // Initialize with system defaults
        purchTable.initFromVendTable(vendTable);  // Initialize from vendor defaults

        // Set specific purchase order fields
        purchTable.PurchId = NumberSeq::newGetNum(PurchParameters::numRefPurchId()).num();
        purchTable.DeliveryDate = systemDateGet() + 7;  // Delivery in 7 days
        purchTable.PurchaseType = PurchaseType::Purch;  // Standard purchase order
        purchTable.PurchStatus = PurchStatus::Backorder;
        purchTable.LanguageId = vendTable.LanguageId;
        purchTable.CurrencyCode = vendTable.Currency;

        // Set delivery address if needed
        purchTable.DeliveryName = vendTable.Name;
        purchTable.DeliveryAddress = vendTable.Address;

        // Create PurchTableType instance for business logic
        // Constructor takes the PurchTable record directly
        purchTableType = PurchTableType::construct(purchTable);

        // Validate before insert
        if (!purchTableType.validateWrite())
        {
            throw error("Purchase order validation failed");
        }

        // Insert the purchase order header
        purchTable.insert();

        // Create purchase order lines
        inventTable = InventTable::find('ITEM-001');  // Replace with your item
        if (inventTable)
        {
            purchLine.clear();
            purchLine.initFromPurchTable(purchTable);
            purchLine.initFromInventTable(inventTable);

            purchLine.PurchId = purchTable.PurchId;
            purchLine.ItemId = inventTable.ItemId;
            purchLine.PurchQty = 10;  // Quantity
            // Use PurchUnit field directly from InventTable
            purchLine.PurchUnit = inventTable.PurchUnit ? inventTable.PurchUnit : inventTable.BOMUnitId;
            purchLine.PurchPrice = 100;  // Unit price
            purchLine.LineAmount = purchLine.calcLineAmount();
            purchLine.DeliveryDate = purchTable.DeliveryDate;
            purchLine.InventDimId = InventDim::findOrCreateBlank().InventDimId;

            // Validate and insert line
            if (!purchLine.validateWrite())
            {
                throw error("Purchase line validation failed");
            }
            purchLine.insert();
        }

        // Check if workflow is enabled for purchase orders
        workflowEnabled = PurchParameters::find().PurchReqApproval == NoYes::Yes;

        if (workflowEnabled)
        {
            // Update status to indicate it needs approval
            purchTable.DocumentStatus = DocumentStatus::PendingApproval;
            purchTable.PurchStatus = PurchStatus::Backorder;  // Keep in backorder until approved
            purchTable.update();

            info(strFmt("Purchase order %1 created and ready for workflow approval", purchTable.PurchId));

            // Note: In AX 2009, workflow submission is typically done through the UI
            // or by calling specific workflow classes if implemented in your system
            // The exact method depends on your workflow configuration
        }
        else
        {
            // If no workflow, optionally confirm the order
            if (Box::yesNo("No workflow enabled. Confirm purchase order now?", DialogButton::No) == DialogButton::Yes)
            {
                // Update to confirmed status
                purchTable.PurchStatus = PurchStatus::Confirmed;
                purchTable.DocumentStatus = DocumentStatus::Confirmed;
                purchTable.update();

                info(strFmt("Purchase order %1 created and confirmed", purchTable.PurchId));
            }
            else
            {
                info(strFmt("Purchase order %1 created in backorder status", purchTable.PurchId));
            }
        }

        ttscommit;
    }
    catch (Exception::Error)
    {
        ttsabort;
        error("Failed to create purchase order");
    }
}
